from pathlib import Path
import re
root = Path('test/modules/tiling_aperiodic')
for path in root.glob('*/*/*_module_test.dart'):
    text = path.read_text()
    m = re.search(r"import 'package:flutter_fractals/[^']+/([^/]+)_module\.dart';\n", text)
    if not m:
        raise SystemExit(f'no module import: {path}')
    module_slug = m.group(1)
    cls = re.search(r'final m = (\w+)\(\);', text).group(1)
    id_ = re.search(r"expect\(m\.id, '([^']+)'\);", text).group(1)
    shader = re.search(r"expect\(m\.shader, '([^']+)'\);", text).group(1)
    import_line = "import '../../shared/ifs_module_contract.dart';\n"
    new = re.sub(r"import 'package:flutter_test/flutter_test\.dart';\n", "", text)
    if import_line not in new:
        new = new.replace('\nvoid main()', import_line + '\nvoid main()')
    new = re.sub(r"void main\(\) \{.*\n\}\n\Z", f"void main() {{\n  defineIFSModuleContractTests(\n    '{cls}',\n    {cls}.new,\n    id: '{id_}',\n    shader: '{shader}',\n  );\n}}\n", new, flags=re.S)
    path.write_text(new)
